func dispatchW_ppi(slot uint32, recv unsafe.Pointer) (unsafe.Pointer, unsafe.Pointer, uint64) {
	var pw [0]unsafe.Pointer
	var sw [0]uint64
	var fw [0]float64
	var rpw [2]unsafe.Pointer
	var rsw [1]uint64
	var rfw [0]float64
	if core := slotPoolW_ppi[slot]; core != nil {
		core(recv, pw[:], sw[:], fw[:], rpw[:], rsw[:], rfw[:])
	}
	return rpw[0], rpw[1], rsw[0]
}

